const now = new Date();
const today = now.toISOString().slice(0, 10);
const currentMonth = now.toISOString().slice(0, 7);

// ── Monthly income estimate ───────────────────────────────────────────────────
// Set this to your expected monthly take-home (after taxes and deductions).
// Update whenever your pay changes.
const monthlyIncome = 0; // REPLACE: your monthly net income in dollars

// ── Funding template ─────────────────────────────────────────────────────────
// HOW TO FILL THIS IN:
//   1. Run Workflow 00 (Discovery) to get your category IDs
//   2. Copy each categoryId from the Discovery output
//   3. Set the amount for each category
//   4. Delete rows that don't apply to your budget
//
// type: 'fixed'     = exact dollar amount every month
// type: 'remainder' = gets whatever is left after all fixed items run
// skip: true        = exclude this category from auto-funding
const fundingTemplate = [

  // ── DEBT MINIMUMS (fund first) ────────────────────────────────────────────
  { name: 'Mortgage / Rent',    categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Auto Loan',          categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Personal Loan',      categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },

  // ── HOUSING ───────────────────────────────────────────────────────────────
  { name: 'Internet',           categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Gas (Utility)',      categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Electric',           categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Water',              categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Mobile Phone',       categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Streaming Services', categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },

  // ── AUTO ──────────────────────────────────────────────────────────────────
  { name: 'Gas (Auto)',         categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Auto Insurance',     categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Auto Maintenance',   categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },

  // ── FOOD ──────────────────────────────────────────────────────────────────
  { name: 'Groceries',          categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Dining Out',         categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },

  // ── PERSONAL ──────────────────────────────────────────────────────────────
  { name: 'Health & Medical',   categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Personal Care',      categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Entertainment',      categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },
  { name: 'Misc',               categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },

  // ── SAVINGS ───────────────────────────────────────────────────────────────
  { name: 'Emergency Fund',     categoryId: 'GET_FROM_WF00', amount: 0, type: 'fixed' },

  // ── DEBT ATTACK (remainder after all fixed) ───────────────────────────────
  // Change the name and categoryId to whichever debt you are attacking.
  // 'remainder' type gets everything left over after fixed items are funded.
  { name: 'Extra Debt Payment', categoryId: 'GET_FROM_WF00', amount: 0, type: 'remainder' },
];

return [{
  json: {
    bridgeUrl:        'http://actual-bridge:3788',
    telegramChatId:   'REPLACE_WITH_YOUR_TELEGRAM_CHAT_ID',
    currentMonth,
    today,
    monthlyIncome,
    fundingTemplate,
  }
}];

const config = $input.item.json;
const today = config.today;

// Filter template by active dates
const template = config.fundingTemplate.filter(cat => {
  if (cat.skip) return false;
  if (cat.activeUntil && today > cat.activeUntil) return false;
  if (cat.activeAfter && today <= cat.activeAfter) return false;
  return true;
});

// Sum fixed amounts
const fixedTotal = template
  .filter(c => c.type === 'fixed')
  .reduce((sum, c) => sum + c.amount, 0);

const remainder = Math.max(0, config.monthlyIncome - fixedTotal);
const remainderCats = template.filter(c => c.type === 'remainder');
const perRemainder = remainderCats.length > 0 ? remainder / remainderCats.length : 0;

// Assign final amounts
const finalTemplate = template.map(cat => ({
  ...cat,
  finalAmount: cat.type === 'remainder' ? perRemainder : cat.amount,
  amountCents: Math.round((cat.type === 'remainder' ? perRemainder : cat.amount) * 100),
}));

// Emit one item per category for the HTTP loop
return finalTemplate.map(cat => ({
  json: {
    ...config,
    category: cat,
    fixedTotal,
    remainder,
    summaryLines: finalTemplate.map(c => c.name + ': $' + c.finalAmount.toFixed(0)),
  }
}));

const items = $input.all();
if (items.length === 0) return [{ json: { skip: true } }];

// Pull config from the first item - use safe fallbacks since 
// HTTP response may have replaced some properties
const item = items[0].json;
// Config values are lost after HTTP loop — pull directly from Config node
const config = $('Config + Funding Template').first().json;
const month = new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

const monthlyIncome = config.monthlyIncome || 0;
const fixedTotal = item.fixedTotal || 0;
const remainder = item.remainder || 0;
const summaryLines = item.summaryLines || [];

let msg = month + ' Budget Auto-Funded\n\n';
msg += 'Income estimate: $' + monthlyIncome.toLocaleString() + '\n';
msg += 'Fixed obligations: $' + fixedTotal.toFixed(0) + '\n';
msg += 'Debt attack remainder: $' + remainder.toFixed(0) + '\n\n';
msg += 'Funded:\n';
for (const line of summaryLines) {
  msg += '  - ' + line + '\n';
}
msg += '\nBudget is live in Actual. Have a great month.';

return [{ json: { 
  monthlyIncome,
  fixedTotal,
  remainder,
  summaryLines,
  telegramMessage: msg,
  telegramChatId: config.telegramChatId
} }];
